1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	type Item = { type: string };
11	type QuoteStep = { op: "quote"; items: Item[] };
12	type Input = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
13	type QuoteResult = { premium: number };
14	
15	const itemPremium = (item: Item): number => {
16	  const base = BASE_PREMIUM[item.type];
17	  return base + base * FIRST_INSURANCE_RATE;
18	};
19	
20	const quotePremium = (step: QuoteStep): QuoteResult => {
21	  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
22	  return { premium: itemsTotal + PROCESSING_FEE };
23	};
24	
25	export const run = (input: Input): { results: QuoteResult[] } => ({
26	  results: input.steps.map(quotePremium),
27	});
